def silver_medal_score(scores):
    unique_scores = sorted(set(scores), reverse=True)
    if len(unique_scores) < 2:
        return -1
    return unique_scores[1]

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_distinct(self):
        self.assertEqual(silver_medal_score([90, 80, 70, 60]), 80)

    def test_duplicates_at_top(self):
        self.assertEqual(silver_medal_score([100, 100, 90, 80]), 90)

    def test_all_same(self):
        self.assertEqual(silver_medal_score([50, 50, 50]), -1)

    def test_hidden_two_elements(self):
        self.assertEqual(silver_medal_score([10, 20]), 10)

    def test_hidden_single_element(self):
        self.assertEqual(silver_medal_score([5]), -1)

    def test_hidden_ascending(self):
        self.assertEqual(silver_medal_score([1, 2, 3, 4, 5]), 4)

    def test_hidden_duplicates_in_middle(self):
        self.assertEqual(silver_medal_score([100, 90, 90, 80]), 90)

    def test_hidden_zero_included(self):
        self.assertEqual(silver_medal_score([0, 0, 1]), 0)

    def test_hidden_large_list(self):
        self.assertEqual(silver_medal_score([7, 7, 7, 3, 3, 3, 5, 5]), 5)

    def test_hidden_two_same(self):
        self.assertEqual(silver_medal_score([42, 42]), -1)

if __name__ == '__main__':
    unittest.main()
